function applyUniqueIcons() {
  document.querySelectorAll('[data-tool-handler]').forEach(function(el) {
    var handler = el.dataset.toolHandler;
    if (!handler || !TG_UNIQUE_ICONS[handler]) return;
    var iconEl = el.querySelector('.tg-tool-card__icon, .tg-tool-icon, [class*="tool-icon"], [class*="card-icon"]');
    if (iconEl) {
      iconEl.innerHTML = TG_UNIQUE_ICONS[handler];
      iconEl.style.width = '48px';
      iconEl.style.height = '48px';
      iconEl.style.display = 'flex';
      iconEl.style.alignItems = 'center';
      iconEl.style.justifyContent = 'center';
    }
  });
}

document.addEventListener('DOMContentLoaded', applyUniqueIcons);
window.TGApplyIcons = applyUniqueIcons;
window.TG_UNIQUE_ICONS = TG_UNIQUE_ICONS;
